map.on('mousemove', 'stores', (e) => {
  if (map.getLayer('stores-hover')) {
    map.removeLayer('stores-hover');
  }
  map.addLayer({
    id: 'stores-hover',
    type: 'circle',
    source: 'stores',
    filter: ['==', ['id'], e.features[0].id],
